questionvariables.text:
/* 1. Pick radii such that (R-r) is a simple small number */
R: 10 + rand(6);
r: 5 + rand(3);
diff: R - r;

/* 2. Pick h_frustum as a multiple of the difference to keep H a whole number */
h_factor: 2 + rand(3); 
h_frustum: h_factor * diff;

/* 3. Calculate full height H */
H: (R * h_frustum) / diff;

/* 4. NEW: Calculate Slant Height L using Pythagoras */
/* We use float() because this will likely be a decimal */
L: R^2 + H^2;

/* 5. Calculation variables for the General Feedback */
bracket_value: R^2 + R*r + r^2;
height_bracket_value: bracket_value * h_frustum;
V: (1/3) * %pi * height_bracket_value;
ta: V / 1000;

/* 6. JSXGraph Scaling */
Rdraw: R/4;
rdraw: r/4;
hdraw: h_frustum/4;
Hdraw: H/4;
